16	import type { Plugin, StartupContext } from '@shardworks/nexus-core';
17	import { guild, generateId } from '@shardworks/nexus-core';
18	import { tool } from '@shardworks/tools-apparatus';
19	import type { StacksApi, Book, WhereClause } from '@shardworks/stacks-apparatus';
20	
21	import type {
22	  ClerkApi,
