172	      const writ = await writs.get(id);
173	      if (!writ) {
174	        throw new Error(`Writ "${id}" not found.`);
175	      }
176	      return writ;
177	    },
178	
179	    async list(filters?: WritFilters): Promise<WritDoc[]> {
180	      const where = buildWhereClause(filters);
181	      const limit = filters?.limit ?? 20;
182	      const offset = filters?.offset;
183	
184	      return writs.find({
185	        where,
186	        orderBy: ['createdAt', 'desc'],
187	        limit,
188	        ...(offset !== undefined ? { offset } : {}),
189	      });
190	    },
191	
192	    async count(filters?: WritFilters): Promise<number> {
193	      const where = buildWhereClause(filters);
194	      return writs.count(where);
195	    },
196	
197	    async link(sourceId: string, targetId: string, type: string): Promise<WritLinkDoc> {
198	      if (sourceId === targetId) {
199	        throw new Error(`Cannot link a writ to itself: "${sourceId}".`);
200	      }
201	      if (!type || !type.trim()) {
202	        throw new Error('Link type must be a non-empty string.');
203	      }
204	
205	      const source = await writs.get(sourceId);
206	      if (!source) {
207	        throw new Error(`Writ "${sourceId}" not found.`);
208	      }
209	      const target = await writs.get(targetId);
210	      if (!target) {
211	        throw new Error(`Writ "${targetId}" not found.`);
212	      }
213	
214	      const id = `${sourceId}:${targetId}:${type}`;
215	      const existing = await links.get(id);
216	      if (existing) {
217	        return existing;
218	      }
219	
220	      const doc: WritLinkDoc = {
221	        id,
222	        sourceId,
223	        targetId,
224	        type,
225	        createdAt: new Date().toISOString(),
226	      };
227	      await links.put(doc);
228	      return doc;
229	    },
230	
231	    async links(writId: string): Promise<WritLinks> {
232	      const [outbound, inbound] = await Promise.all([
233	        links.find({ where: [['sourceId', '=', writId]] }),
234	        links.find({ where: [['targetId', '=', writId]] }),
235	      ]);
236	      return { outbound, inbound };
237	    },
238	
239	    async unlink(sourceId: string, targetId: string, type: string): Promise<void> {
240	      const id = `${sourceId}:${targetId}:${type}`;
241	      await links.delete(id);
242	    },
243	
244	    async transition(id: string, to: WritStatus, fields?: Partial<WritDoc>): Promise<WritDoc> {
245	      const writ = await writs.get(id);
246	      if (!writ) {
247	        throw new Error(`Writ "${id}" not found.`);
248	      }
249	
250	      const allowedFrom = ALLOWED_FROM[to];
251	      if (!allowedFrom.includes(writ.status)) {
252	        throw new Error(
253	          `Cannot transition writ "${id}" to "${to}": status is "${writ.status}", expected one of: ${allowedFrom.join(', ')}.`,
254	        );
255	      }
256	
257	      const now = new Date().toISOString();
258	      const isTerminal = TERMINAL_STATUSES.has(to);
259	
260	      // Strip managed fields — callers cannot override id, status, or timestamps
261	      // controlled by the status machine.
262	      const { id: _id, status: _status, createdAt: _c, updatedAt: _u,
263	        acceptedAt: _a, resolvedAt: _r, ...safeFields } = (fields ?? {}) as WritDoc;
264	
265	      const patch: Partial<Omit<WritDoc, 'id'>> = {
266	        status: to,
267	        updatedAt: now,
268	        ...(to === 'active' ? { acceptedAt: now } : {}),
269	        ...(isTerminal ? { resolvedAt: now } : {}),
270	        ...safeFields,
271	      };
272	
273	      return writs.patch(id, patch);
274	    },
275	  };
276	
277	  // ── writ-types tool ──────────────────────────────────────────────
278	
279	  const writTypesTool = tool({
280	    name: 'writ-types',
281	    description: 'List available writ types for this guild',
282	    instructions:
283	      'Returns the available writ types including built-in types, types declared ' +
284	      'in guild config, and types contributed by kits. Each entry includes the ' +
285	      'type name, optional description, and whether it is the default type.',
286	    params: {},
