1	/**
2	 * Stacks core — shared implementation logic for both the production
3	 * apparatus (stacks.ts) and the testable harness (testable-stacks.ts).
4	 *
5	 * This module contains ALL read/write/transaction/CDC logic. The two
6	 * consumer modules only add their own wiring: the apparatus adds guild()
7	 * startup and plugin schema reconciliation; the testable harness adds
8	 * nothing (just exposes createApi() directly).
9	 *
10	 * This ensures behavioral identity by construction, not by copy-paste.
11	 */
12	
13	import type {
14	  BackendTransaction,
15	  BookRef,
16	  InternalQuery,
17	  StacksBackend,
18	} from './backend.ts';
19	
20	import type {
21	  Book,
22	  BookEntry,
23	  BookQuery,
24	  ListOptions,
25	  ReadOnlyBook,
26	  StacksApi,
27	  TransactionContext,
28	  WatchOptions,
29	  WhereClause,
30	  ChangeHandler,
31	} from './types.ts';
32	
33	import { CdcRegistry, coalesceEvents, type BufferedEvent } from './cdc.ts';
34	import { translateQuery, translateWhereClause } from './query.ts';
35	import { normalizeOrderBy, compareByOrderEntries } from './field-utils.ts';
36	
37	// ── Constants ────────────────────────────────────────────────────────
38	
39	const MAX_CASCADE_DEPTH = 16;
40	
41	// ── Active transaction state ──────────────────────────────────────────
42	
43	interface ActiveTransaction {
44	  backendTx: BackendTransaction;
45	  eventBuffer: BufferedEvent[];
46	  depth: number;
47	}
48	
49	// ── Book handle implementation ────────────────────────────────────────
50	
51	function createBookHandle<T extends BookEntry>(
52	  ref: BookRef,
53	  core: StacksCore,
54	  writable: boolean,
55	): Book<T> {
56	  const readMethods: ReadOnlyBook<T> = {
57	    async get(id: string): Promise<T | null> {
58	      return core.doGet(ref, id) as T | null;
59	    },
60	
61	    async find(query: BookQuery): Promise<T[]> {
62	      return core.doFind(ref, query) as Promise<T[]>;
63	    },
64	
65	    async list(options?: ListOptions): Promise<T[]> {
66	      // Cast needed: ListOptions spreads into BookQuery but the Pagination
67	      // discriminated union can't be inferred from optional fields.
68	      return core.doFind(ref, {
69	        orderBy: options?.orderBy,
70	        limit: options?.limit,
71	        offset: options?.offset,
72	      } as BookQuery) as Promise<T[]>;
73	    },
74	
75	    async count(where?: WhereClause | { or: WhereClause[] }): Promise<number> {
76	      return core.doCount(ref, where);
77	    },
78	  };
79	
80	  if (!writable) {
81	    return readMethods as Book<T>;
82	  }
83	
84	  return {
85	    ...readMethods,
86	
87	    async put(entry: T): Promise<void> {
88	      await core.doPut(ref, entry);
89	    },
90	
91	    async patch(id: string, fields: Partial<Omit<T, 'id'>>): Promise<T> {
92	      return (await core.doPatch(ref, id, fields as Record<string, unknown>)) as T;
93	    },
94	
95	    async delete(id: string): Promise<void> {
96	      await core.doDelete(ref, id);
97	    },
98	  };
99	}
100	
101	// ── Stacks core implementation ───────────────────────────────────────
102	
103	export class StacksCore {
104	  private readonly cdc = new CdcRegistry();
105	  private activeTx: ActiveTransaction | null = null;
106	
107	  constructor(readonly backend: StacksBackend) {}
108	
109	  // ── API surface ───────────────────────────────────────────────────
110	
111	  createApi(): StacksApi {
112	    const self = this;
113	
114	    return {
115	      book<T extends BookEntry>(ownerId: string, name: string): Book<T> {
116	        return createBookHandle<T>({ ownerId, book: name }, self, true);
117	      },
118	
119	      readBook<T extends BookEntry>(ownerId: string, name: string): ReadOnlyBook<T> {
120	        return createBookHandle<T>({ ownerId, book: name }, self, false) as ReadOnlyBook<T>;
121	      },
122	
123	      watch<T extends BookEntry>(
124	        ownerId: string,
125	        bookName: string,
126	        handler: ChangeHandler<T>,
127	        options?: WatchOptions,
128	      ): void {
129	        self.cdc.watch(
130	          ownerId,
131	          bookName,
132	          handler as ChangeHandler,
133	          options,
134	        );
135	      },
136	
137	      async transaction<R>(fn: (tx: TransactionContext) => Promise<R>): Promise<R> {
138	        return self.runTransaction(fn);
139	      },
140	    };
141	  }
142	
143	  // ── Transaction management ────────────────────────────────────────
144	
145	  async runTransaction<R>(fn: (tx: TransactionContext) => Promise<R>): Promise<R> {
146	    // If already in a transaction, just run (no nesting — flattened)
147	    if (this.activeTx) {
148	      const txCtx = this.createTransactionContext();
149	      return fn(txCtx);
150	    }
151	
152	    // Create new transaction
153	    const backendTx = this.backend.beginTransaction();
154	    const eventBuffer: BufferedEvent[] = [];
155	    this.activeTx = { backendTx, eventBuffer, depth: 0 };
156	
157	    try {
158	      const txCtx = this.createTransactionContext();
159	      const result = await fn(txCtx);
160	
161	      backendTx.commit();
162	      const coalesced = coalesceEvents(eventBuffer);
163	      this.activeTx = null;
164	
165	      // Fire Phase 2 handlers (after commit)
166	      await this.cdc.firePhase2(coalesced);
167	
168	      return result;
169	    } catch (err) {
170	      try { backendTx.rollback(); } catch { /* already rolled back */ }
171	      this.activeTx = null;
172	      throw err;
173	    }
174	  }
175	
176	  private createTransactionContext(): TransactionContext {
177	    const self = this;
178	    return {
179	      book<T extends BookEntry>(ownerId: string, name: string): Book<T> {
180	        return createBookHandle<T>({ ownerId, book: name }, self, true);
181	      },
182	      readBook<T extends BookEntry>(ownerId: string, name: string): ReadOnlyBook<T> {
183	        return createBookHandle<T>({ ownerId, book: name }, self, false) as ReadOnlyBook<T>;
184	      },
185	    };
186	  }
187	
188	  // ── Write operations (called by book handles) ─────────────────────
189	
190	  async doPut(ref: BookRef, entry: BookEntry): Promise<void> {
191	    if (!this.activeTx) {
192	      return this.runTransaction(async () => this.doPutInTx(ref, entry));
193	    }
194	    return this.doPutInTx(ref, entry);
195	  }
196	
197	  private async doPutInTx(ref: BookRef, entry: BookEntry): Promise<void> {
198	    const tx = this.requireTx();
199	    this.cdc.lock();
200	
201	    // Check cascade depth
202	    tx.depth++;
203	    if (tx.depth > MAX_CASCADE_DEPTH) {
204	      throw new Error(
205	        `[stacks] Maximum cascade depth (${MAX_CASCADE_DEPTH}) exceeded. ` +
206	        `This usually means a CDC handler is triggering itself recursively.`,
207	      );
208	    }
209	
210	    const needPrev = this.cdc.hasWatchers(ref.ownerId, ref.book);
211	    const result = tx.backendTx.put(ref, entry, { withPrev: needPrev });
212	
213	    const event: BufferedEvent = {
214	      ref: `${ref.ownerId}/${ref.book}`,
215	      ownerId: ref.ownerId,
216	      book: ref.book,
217	      docId: entry.id,
218	      type: result.created ? 'create' : 'update',
219	      entry,
220	      prev: result.prev,
221	    };
222	    tx.eventBuffer.push(event);
223	
224	    // Fire Phase 1 handlers (inside the transaction)
225	    if (result.created) {
226	      await this.cdc.firePhase1(ref.ownerId, ref.book, {
227	        type: 'create', ownerId: ref.ownerId, book: ref.book, entry,
228	      });
229	    } else {
230	      await this.cdc.firePhase1(ref.ownerId, ref.book, {
231	        type: 'update', ownerId: ref.ownerId, book: ref.book, entry, prev: result.prev!,
232	      });
233	    }
234	
235	    tx.depth--;
236	  }
237	
238	  async doPatch(ref: BookRef, id: string, fields: Record<string, unknown>): Promise<BookEntry> {
239	    if (!this.activeTx) {
240	      let result!: BookEntry;
241	      await this.runTransaction(async () => {
