1	/**
2	 * Tier 2 — CDC Behavioral Correctness conformance tests.
3	 *
4	 * Failures here mean the CDC contract is violated.
5	 */
6	
7	import { describe, it, beforeEach, afterEach } from 'node:test';
8	import assert from 'node:assert/strict';
9	
10	import type { StacksBackend } from '../backend.ts';
11	import type { BookEntry } from '../types.ts';
12	import {
13	  createTestStacks,
14	  collectEvents,
15	  seedDocument,
16	  spyingBackendFactory,
17	  assertCreateEvent,
18	  assertUpdateEvent,
19	  assertDeleteEvent,
20	  OWNER,
21	  BOOK,
22	  REF,
23	  type TestStacks,
24	} from './helpers.ts';
25	
26	export function tier2Cdc(backendFactory: () => StacksBackend): void {
27	  describe('Tier 2 — CDC Behavioral Correctness', () => {
28	    let t: TestStacks;
29	
30	    beforeEach(() => {
31	      t = createTestStacks(backendFactory);
32	      t.ensureBook(OWNER, BOOK);
33	    });
34	
35	    afterEach(() => {
36	      t.backend.close();
37	    });
38	
39	    it('2.1 Put (new document) fires create event', async () => {
40	      const events = collectEvents(t.stacks, OWNER, BOOK);
41	      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
42	      await book.put({ id: 'a', name: 'Alice' });
43	
44	      assert.strictEqual(events.length, 1);
45	      assertCreateEvent(events[0], { entry: { id: 'a', name: 'Alice' } });
46	    });
47	
48	    it('2.2 Put (existing document) fires update event with prev', async () => {
49	      seedDocument(t.backend, REF, { id: 'a', name: 'Alice' });
50	      const events = collectEvents(t.stacks, OWNER, BOOK);
51	      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
52	      await book.put({ id: 'a', name: 'Bob' });
53	
54	      assert.strictEqual(events.length, 1);
55	      assertUpdateEvent(events[0], {
56	        entry: { id: 'a', name: 'Bob' },
57	        prev: { id: 'a', name: 'Alice' },
58	      });
59	    });
60	
61	    it('2.3 Patch fires update event with prev', async () => {
62	      seedDocument(t.backend, REF, { id: 'a', name: 'Alice', score: 10 });
63	      const events = collectEvents(t.stacks, OWNER, BOOK);
64	      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
65	      await book.patch('a', { score: 20 });
66	
67	      assert.strictEqual(events.length, 1);
68	      assertUpdateEvent(events[0], {
69	        entry: { id: 'a', name: 'Alice', score: 20 },
70	        prev: { id: 'a', name: 'Alice', score: 10 },
71	      });
72	    });
73	
74	    it('2.4 Delete fires delete event with prev', async () => {
75	      seedDocument(t.backend, REF, { id: 'a', name: 'Alice' });
76	      const events = collectEvents(t.stacks, OWNER, BOOK);
77	      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
78	      await book.delete('a');
79	
80	      assert.strictEqual(events.length, 1);
81	      assertDeleteEvent(events[0], { id: 'a', prev: { id: 'a', name: 'Alice' } });
82	    });
83	
84	    it('2.5 Delete of nonexistent document fires no event', async () => {
85	      const events = collectEvents(t.stacks, OWNER, BOOK);
86	      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
87	      await book.delete('nonexistent');
88	
89	      assert.strictEqual(events.length, 0);
90	    });
91	
92	    it('2.6 No pre-read when no handlers are registered', async () => {
93	      // Use a spying backend to verify put() is called with withPrev: false
94	      const spy = spyingBackendFactory(backendFactory);
95	      const spyT = createTestStacks(spy.factory);
96	      spyT.ensureBook(OWNER, BOOK);
97	
98	      // No watch() calls — no handlers registered
99	      const book = spyT.stacks.book<BookEntry>(OWNER, BOOK);
100	      await book.put({ id: 'a', name: 'Alice' });
101	
102	      // The put should have been called with withPrev: false (no pre-read needed)
103	      const putCalls = spy.putCalls.filter(
104	        c => c.ref.ownerId === OWNER && c.ref.book === BOOK,
105	      );
106	      assert.strictEqual(putCalls.length, 1);
107	      assert.strictEqual(putCalls[0].withPrev, false);
108	
109	      spyT.backend.close();
110	    });
111	
112	    it('2.6a Put with identical document fires update event', async () => {
113	      seedDocument(t.backend, REF, { id: 'a', name: 'Alice' });
114	      const events = collectEvents(t.stacks, OWNER, BOOK);
115	      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
116	      await book.put({ id: 'a', name: 'Alice' });
117	
118	      assert.strictEqual(events.length, 1);
119	      assertUpdateEvent(events[0], {
120	        entry: { id: 'a', name: 'Alice' },
121	        prev: { id: 'a', name: 'Alice' },
122	      });
123	    });
124	
125	    it('2.6b CDC events include ownerId and book fields — create', async () => {
126	      const owner = 'my-plugin';
127	      const bookName = 'tasks';
128	      t.ensureBook(owner, bookName);
129	
130	      const events = collectEvents(t.stacks, owner, bookName);
131	      const book = t.stacks.book<BookEntry>(owner, bookName);
132	
133	      await book.put({ id: 'a', title: 'test' });
134	      assert.strictEqual(events[0].type, 'create');
135	      assert.strictEqual(events[0].ownerId, owner);
136	      assert.strictEqual(events[0].book, bookName);
137	    });
138	
139	    it('2.6b CDC events include ownerId and book fields — update', async () => {
140	      const owner = 'my-plugin';
141	      const bookName = 'tasks';
142	      t.ensureBook(owner, bookName);
143	
144	      // Seed via backend to avoid tripping the CDC lock
145	      seedDocument(t.backend, { ownerId: owner, book: bookName }, { id: 'a', title: 'test' });
146	
147	      const events = collectEvents(t.stacks, owner, bookName);
148	      const book = t.stacks.book<BookEntry>(owner, bookName);
149	
150	      await book.put({ id: 'a', title: 'updated' });
151	      assert.strictEqual(events[0].type, 'update');
152	      assert.strictEqual(events[0].ownerId, owner);
153	      assert.strictEqual(events[0].book, bookName);
154	    });
155	
156	    it('2.6b CDC events include ownerId and book fields — delete', async () => {
157	      const owner = 'my-plugin';
158	      const bookName = 'tasks';
159	      t.ensureBook(owner, bookName);
160	
161	      seedDocument(t.backend, { ownerId: owner, book: bookName }, { id: 'a', title: 'test' });
162	
163	      const events = collectEvents(t.stacks, owner, bookName);
164	      const book = t.stacks.book<BookEntry>(owner, bookName);
165	
166	      await book.delete('a');
167	      assert.strictEqual(events[0].type, 'delete');
168	      assert.strictEqual(events[0].ownerId, owner);
169	      assert.strictEqual(events[0].book, bookName);
170	    });
171	
172	    it('2.7 Phase 1 handler error rolls back the triggering write', async () => {
173	      t.stacks.watch(OWNER, BOOK, async () => {
174	        throw new Error('cascade failed');
175	      }, { failOnError: true });
176	
177	      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
178	      await assert.rejects(
179	        () => book.put({ id: 'a', name: 'Alice' }),
180	        /cascade failed/,
181	      );
182	
183	      const result = await book.get('a');
184	      assert.strictEqual(result, null);
185	    });
186	
187	    it('2.8 Phase 2 handler error does not roll back the write', async () => {
188	      t.stacks.watch(OWNER, BOOK, async () => {
189	        throw new Error('notification failed');
190	      }, { failOnError: false });
191	
192	      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
193	      await book.put({ id: 'a', name: 'Alice' });
194	
195	      const result = await book.get('a');
196	      assert.deepStrictEqual(result, { id: 'a', name: 'Alice' });
197	    });
198	
199	    it('2.9 Phase 1 handlers fire before Phase 2 handlers', async () => {
200	      const order: string[] = [];
201	      t.stacks.watch(OWNER, BOOK, () => { order.push('phase1'); }, { failOnError: true });
202	      t.stacks.watch(OWNER, BOOK, () => { order.push('phase2'); }, { failOnError: false });
203	
204	      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
205	      await book.put({ id: 'a', name: 'Alice' });
206	
207	      assert.deepStrictEqual(order, ['phase1', 'phase2']);
208	    });
209	
210	    it('2.10 Multiple handlers fire in registration order within each phase', async () => {
211	      const order: string[] = [];
212	      t.stacks.watch(OWNER, BOOK, () => { order.push('p1-first'); }, { failOnError: true });
213	      t.stacks.watch(OWNER, BOOK, () => { order.push('p1-second'); }, { failOnError: true });
214	      t.stacks.watch(OWNER, BOOK, () => { order.push('p2-first'); }, { failOnError: false });
215	      t.stacks.watch(OWNER, BOOK, () => { order.push('p2-second'); }, { failOnError: false });
216	
217	      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
218	      await book.put({ id: 'a', name: 'Alice' });
219	
220	      assert.deepStrictEqual(order, ['p1-first', 'p1-second', 'p2-first', 'p2-second']);
221	    });
222	
223	    it('2.11 Phase 1 handler writes are atomic with the trigger', async () => {
224	      const bookNameA = 'booksa';
225	      const bookNameB = 'booksb';
226	      t.ensureBook(OWNER, bookNameA);
227	      t.ensureBook(OWNER, bookNameB);
228	
229	      t.stacks.watch(OWNER, bookNameA, async () => {
230	        const booksB = t.stacks.book<BookEntry>(OWNER, bookNameB);
231	        await booksB.put({ id: 'derived', source: 'a' });
232	      }, { failOnError: true });
233	
234	      const booksA = t.stacks.book<BookEntry>(OWNER, bookNameA);
235	      await booksA.put({ id: 'a', name: 'Alice' });
236	
237	      const resultA = await booksA.get('a');
238	      const resultB = await t.stacks.book<BookEntry>(OWNER, bookNameB).get('derived');
239	      assert.notStrictEqual(resultA, null);
240	      assert.notStrictEqual(resultB, null);
241	    });
242	
243	    it('2.12 Phase 1 handler failure rolls back handler writes AND trigger', async () => {
244	      const bookNameA = 'booksa';
245	      const bookNameB = 'booksb';
246	      t.ensureBook(OWNER, bookNameA);
247	      t.ensureBook(OWNER, bookNameB);
248	
249	      t.stacks.watch(OWNER, bookNameA, async () => {
250	        const booksB = t.stacks.book<BookEntry>(OWNER, bookNameB);
251	        await booksB.put({ id: 'derived', source: 'a' });
252	        throw new Error('cascade failed');
253	      }, { failOnError: true });
254	
255	      const booksA = t.stacks.book<BookEntry>(OWNER, bookNameA);
256	      await assert.rejects(() => booksA.put({ id: 'a', name: 'Alice' }));
257	
258	      const resultA = await booksA.get('a');
259	      const resultB = await t.stacks.book<BookEntry>(OWNER, bookNameB).get('derived');
260	      assert.strictEqual(resultA, null);
261	      assert.strictEqual(resultB, null);
